const item = $input.first().json;
const query = item.query || item.params || {};
const groupBy = (query.group_by || query.groupBy || 'day').toLowerCase();
const valid = ['day', 'week', 'year'];
const period = valid.includes(groupBy) ? groupBy : 'day';
const fromDate = query.from_date || query.from || null;
const toDate = query.to_date || query.to || null;
return [{ json: { period, from_date: fromDate, to_date: toDate } }];

const items = $input.all();
const period = $('Normalize Params').first().json.period;
const data = items.map(i => ({ period: i.json.period, revenue: Number(i.json.revenue), order_count: Number(i.json.order_count || 0) }));
return [{ json: { success: true, group_by: period, data } }];
